+        .expect("disable concurrent mode for deterministic retained-autocommit coverage");
+
+    let schema_sql = "CREATE TABLE msgs(id INTEGER PRIMARY KEY, val TEXT NOT NULL);";
+    c_conn.execute(schema_sql, []).expect("csqlite schema");
